import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, AreaPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface ProductRevenue {
  product: string;
  monthlyRevenue: number[];
}

interface RevenueData {
  revenueByProductLine: ProductRevenue[];
}

export default function Widget() {
  const revenueData = response.data as RevenueData;
  const clipPathId = useId();
  const { primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor, mb: 1 }}>
              Revenue Insights
            </Typography>
            {revenueData.revenueByProductLine.map((product) => (
              <Box key={product.product} sx={{ mb: 2 }}>
                <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                  {product.product}
                </Typography>
                <Box sx={{ width: '100%', height: 150 }}>
                  <ResponsiveChartContainer
                    series={[
                      {
                        type: 'area',
                        data: product.monthlyRevenue,
                        color: accentColor,
                        label: product.product,
                      },
                    ]}
                    xAxis={[
                      {
                        data: product.monthlyRevenue.map((_, index) => index + 1),
                        hide: true,
                      },
                    ]}
                    yAxis={[{ hide: true }]}
                  >
                    <g clipPath={`url(#${clipPathId})`}>
                      <AreaPlot />
                    </g>
                    <ChartsClipPath id={clipPathId} />
                  </ResponsiveChartContainer>
                </Box>
              </Box>
            ))}
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
